+/* Minimal BPF type stubs for RVF eBPF programs.
+ *
+ * This header provides the essential kernel type definitions so that
+ * BPF C programs can compile without requiring the full kernel headers.
+ * In production, replace this with the vmlinux.h generated by:
+ *   bpftool btf dump file /sys/kernel/btf/vmlinux format c
+ */
+
+#ifndef __VMLINUX_H__
+#define __VMLINUX_H__
+
+/* ── Scalar typedefs ─────────────────────────────────────────────── */
+
+typedef unsigned char       __u8;
+typedef unsigned short      __u16;
+typedef unsigned int        __u32;
+typedef unsigned long long  __u64;
+typedef signed char         __s8;
+typedef signed short        __s16;
+typedef signed int          __s32;
+typedef signed long long    __s64;
+
+typedef __u16 __be16;
+typedef __u32 __be32;
+typedef __u64 __be64;
+
+typedef __u16 __sum16;
+
+/* ── Ethernet ────────────────────────────────────────────────────── */
+
+#define ETH_ALEN    6
+#define ETH_P_IP    0x0800
+#define ETH_P_IPV6  0x86DD
+
+struct ethhdr {
+    unsigned char   h_dest[ETH_ALEN];
+    unsigned char   h_source[ETH_ALEN];
+    __be16          h_proto;
+} __attribute__((packed));
+
+/* ── IPv4 ────────────────────────────────────────────────────────── */
+
+#define IPPROTO_TCP   6
+#define IPPROTO_UDP  17
+
+struct iphdr {
+#if defined(__BYTE_ORDER__) && __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
+    __u8  ihl:4,
+          version:4;
+#else
+    __u8  version:4,
+          ihl:4;
+#endif
+    __u8  tos;
+    __be16 tot_len;
+    __be16 id;
+    __be16 frag_off;
+    __u8   ttl;
+    __u8   protocol;
+    __sum16 check;
+    __be32  saddr;
+    __be32  daddr;
+} __attribute__((packed));
+
+/* ── UDP ─────────────────────────────────────────────────────────── */
+
+struct udphdr {
+    __be16 source;
+    __be16 dest;
+    __be16 len;
+    __sum16 check;
+} __attribute__((packed));
+
+/* ── TCP ─────────────────────────────────────────────────────────── */
+
+struct tcphdr {
+    __be16 source;
+    __be16 dest;
+    __be32 seq;
+    __be32 ack_seq;
+#if defined(__BYTE_ORDER__) && __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
+    __u16  res1:4,
+           doff:4,
+           fin:1,
+           syn:1,
+           rst:1,
+           psh:1,
+           ack:1,
+           urg:1,
+           ece:1,
