+           urg:1,
+           ack:1,
+           psh:1,
+           rst:1,
+           syn:1,
+           fin:1;
+#endif
+    __be16 window;
+    __sum16 check;
+    __be16 urg_ptr;
+} __attribute__((packed));
+
+/* ── XDP context ─────────────────────────────────────────────────── */
+
+struct xdp_md {
+    __u32 data;
+    __u32 data_end;
+    __u32 data_meta;
+    __u32 ingress_ifindex;
+    __u32 rx_queue_index;
+    __u32 egress_ifindex;
+};
